const chatBody = document.getElementById("chat-body");
const input = document.getElementById("chat-input");
const sendBtn = document.getElementById("send-btn");

/* Typing Indicator */
const typingIndicator = document.createElement("div");
typingIndicator.className = "typing-indicator hidden";
typingIndicator.innerHTML = `
  <span class="dot"></span>
  <span class="dot"></span>
  <span class="dot"></span>
`;
chatBody.appendChild(typingIndicator);

/* Scroll */
function scrollBottom() {
  chatBody.scrollTop = chatBody.scrollHeight;
}

/* Add User Message */
function addUserMessage(text) {
  const msg = document.createElement("div");
  msg.className = "message user-msg";
  msg.innerHTML = `<div class="message-bubble">${text}</div>`;
  chatBody.appendChild(msg);
  scrollBottom();
}

/* Add Bot Message */
function addBotMessage(text) {
  const msg = document.createElement("div");
  msg.className = "message bot-msg";
  msg.innerHTML = `<div class="message-bubble">${text}</div>`;
  chatBody.appendChild(msg);
  scrollBottom();
}

/* Typing Controls */
function showTyping() {
  typingIndicator.classList.remove("hidden");
  chatBody.appendChild(typingIndicator);
  scrollBottom();
}

function hideTyping() {
  typingIndicator.classList.add("hidden");
}

/* Therapist-style replies */
function therapistReply(userText) {
  const responses = [
    "Thank you for sharing that 💙 Can you tell me a little more about how this has been affecting you?",
    "That sounds really difficult. I’m glad you’re talking about it here.",
    "I hear you. What do you feel is the hardest part of this right now?",
    "You’re not alone in feeling this way. Let’s take this one step at a time.",
    "It makes sense that you’d feel like this given what you’re experiencing."
  ];
  return responses[Math.floor(Math.random() * responses.length)];
}

/* Send Message */
function sendMessage() {
  const text = input.value.trim();
  if (!text) return;

  addUserMessage(text);
  input.value = "";

  showTyping();

  setTimeout(() => {
    hideTyping();
    addBotMessage(therapistReply(text));
  }, 1600);
}

sendBtn.addEventListener("click", sendMessage);
input.addEventListener("keypress", (e) => {
  if (e.key === "Enter") sendMessage();
});

/* Initial Message */
window.onload = () => {
  addBotMessage(
    "Hi 👋 I’m your AI mental health assistant. I’m here to listen. How are you feeling today?"
  );
};
